import _pickle as cPickle
import base64

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        token_bytes = base64.b64decode(token_str)
        token_obj = cPickle.loads(token_bytes)
        return token_obj
    except (base64.binascii.Error, cPickle.UnpicklingError, EOFError):
        return None

